/*global process*/
//This is page where we are redirected to after oAuth login
//It shall be momentarily shown inside the popup before the popup shall be automatically closed by the code that invokes it
import React, { useEffect } from 'react';

import FullWidthPageLayout from '@layouts/FullWidthPage';
import { Seo_noIndex } from '@components/Seo';

export default function AppAngelOne_oAuthRedirectPage() {
	const readTokenFromAuthWindowRedirectUrl_n_setStorage = async () => {
		try {
			const redirectUrl = window.location.href;
			if (!redirectUrl) return;
			let m = redirectUrl.match(/[#?](.*)/);
			if (!m || m.length < 1) return;
			let params = new URLSearchParams(m[1].split('#')[0]);
			const auth_token = params.get('auth_token');
			const feed_token = params.get('feed_token');
			if (!auth_token || !feed_token) return;

			//here fetch user profile
			// const publicIpResp = await fetch('https://api.ipify.org?format=json');
			// const publicIpData = await publicIpResp.json();
			const randomGeneratedMacAdr = 'XX:XX:XX:XX:XX:XX'.replace(/X/g, function () {
				//https://stackoverflow.com/questions/24621721/how-would-one-generate-a-mac-address-in-javascript
				return '0123456789ABCDEF'.charAt(Math.floor(Math.random() * 16));
			}); //same mac addr may be required to be used when calling subsequent GET/POST APIs or when logging-out
			const profileResponse = await fetch('https://apiconnect.angelbroking.com/rest/secure/angelbroking/user/v1/getProfile', {
				headers: {
					Authorization: 'Bearer ' + auth_token,
					'Content-Type': 'application/json',
					Accept: 'application/json',
					'X-UserType': 'USER',
					'X-SourceID': 'WEB',
					// 'X-ClientLocalIP': '192.168.168.168',
					// 'X-ClientPublicIP': publicIpData.ip, //'CLIENT_PUBLIC_IP',
					'X-MACAddress': randomGeneratedMacAdr,
					'X-PrivateKey': process.env.GATSBY_ANGELONE_API_KEY,
				},
			}).catch((err) => {
				throw new Error('Error fetching profile data');
			});
			const profileData = await profileResponse.json();
			if (profileData.message !== 'SUCCESS' || profileData.errorcode !== '') throw new Error('Error fetching profile data');
			// console.log('AngelOne profile data:', profileData.data);
			// setAuthToken(auth_token);
			// setFeedToken(feed_token);
			// setId(profileData.data.clientcode);
			// setName(profileData.data.name);
			// setEmail(profileData.data.email);
			// setMacAdr(randomGeneratedMacAdr);
			//here maybe save it in storage
			localStorage.setItem(
				'angelOneUser',
				JSON.stringify({
					atk: auth_token,
					ftk: feed_token,
					id: profileData.data.clientcode,
					nm: profileData.data.name,
					eml: profileData.data.email,
					t: Math.ceil(Date.now() / 1000), //login-time
					// mac: randomGeneratedMacAdr,
				}),
			);
		} catch (err) {
			console.error(err.message || 'Error while authenticating with AngelOne! Kindly re-login');
			return;
		}
	};
	useEffect(() => {
		(async () => {
			await readTokenFromAuthWindowRedirectUrl_n_setStorage();
		})();
	}, []);
	return <FullWidthPageLayout>Successfully logged into AngelOne</FullWidthPageLayout>;
}

export function Head() {
	return <Seo_noIndex />;
}
